#include <vector>
#include <queue>
#include <algorithm>

using namespace std;

long long solve(long long n, vector<vector<long long>> edges, long long k) {
    // Sort edges by time
    sort(edges.begin(), edges.end(), [](const vector<long long>& a, const vector<long long>& b) {
        return a[2] < b[2];
    });

    // Find max time
    long long max_time = 0;
    for (auto& e : edges) {
        if (e[2] > max_time) {
            max_time = e[2];
        }
    }

    // Function to check if t is valid
    auto check = [&](long long t) -> bool {
        vector<vector<long long>> adj(n);
        for (auto& e : edges) {
            if (e[2] > t) {
                adj[e[0]].push_back(e[1]);
                adj[e[1]].push_back(e[0]);
            }
        }

        vector<bool> visited(n, false);
        int components = 0;

        for (int i = 0; i < n; ++i) {
            if (!visited[i]) {
                ++components;
                queue<int> q;
                q.push(i);
                visited[i] = true;
                while (!q.empty()) {
                    int u = q.front();
                    q.pop();
                    for (int v : adj[u]) {
                        if (!visited[v]) {
                            visited[v] = true;
                            q.push(v);
                        }
                    }
                }
            }
        }

        return components >= k;
    };

    long long low = 0, high = max_time;
    long long answer = max_time;

    while (low <= high) {
        long long mid = (low + high) / 2;
        if (check(mid)) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    return answer;
}
